const body = $input.first().json.body;
if (!body || !body.owner || !body.repo || !body.token) throw new Error('owner, repo, token required');
return [{ json: body }];

const verify = $('Extract body').first().json;
const portfolioRes = $('Get portfolio.json').first().json;
const historyRes = $('Get history.json').first().json;
const memosRes = $('Get memos.json').first().json;
const commitsRes = $('List commits').first().json;

function decode(b64) { try { return Buffer.from(b64, 'base64').toString('utf8'); } catch { return ''; } }
function parseFile(res) {
  if (!res || !res.content) return null;
  try { return JSON.parse(decode(res.content)); } catch { return null; }
}

const portfolio = parseFile(portfolioRes);
if (!portfolio || !Array.isArray(portfolio.items)) throw new Error('portfolio.json missing or invalid — run bootstrap first');

const history = parseFile(historyRes) || { entries: [] };
const memos = (parseFile(memosRes) || { memos: [] }).memos || [];
const commits = Array.isArray(commitsRes) ? commitsRes.slice(0, 30).map(c => ({ sha: c.sha?.slice(0,7), message: (c.commit?.message || '').split('\n')[0], date: c.commit?.author?.date?.slice(0,10) })) : [];

const itemsBrief = portfolio.items.map(i => ({ id: i.id, type: i.type, section: i.section, title: i.title, description: i.description, tags: i.tags }));
const historyBrief = (history.entries || []).map(e => ({ date: e.date, target_id: e.target_id, target_title: e.target_title, ai_suggestion: e.ai_suggestion, user_decision: e.user_decision, user_reason: e.user_reason }));

const prompt = `당신은 개발자 포트폴리오를 점검하는 큐레이션 어시스턴트입니다.

현재 포트폴리오 manifest, 최근 컨텍스트(커밋·메모), 과거 큐레이션 히스토리를 보고 add/remove/keep 제안을 JSON으로 출력하세요.

[현재 포트폴리오 manifest items]
${JSON.stringify(itemsBrief, null, 2)}

[최근 GitHub 커밋 (30개)]
${JSON.stringify(commits, null, 2)}

[직접 입력 메모]
${JSON.stringify(memos, null, 2)}

[과거 큐레이션 히스토리]
${JSON.stringify(historyBrief, null, 2)}

출력 규칙:
- 반드시 다음 JSON 스키마만 출력: { "suggestions": [{ "target_id": "...", "target_title": "...", "suggestion": "add|remove|keep", "ai_reason": "한국어 한두 문장" }] }
- target_id: 기존 items의 id를 그대로 쓰거나(remove/keep), 신규 추가 시 "suggested-{kebab-slug}" 형식
- target_title: 사람이 읽을 짧은 제목
- suggestion: 사용자 메모와 히스토리를 우선 반영. 과거에 거부한 항목은 같은 근거로 다시 제안하지 말 것
- 제안 개수는 1~5개. 너무 일반적인 제안 금지
- ai_reason은 메모/커밋/히스토리의 구체적 근거 인용
`;

return [{ json: { owner: verify.owner, repo: verify.repo, token: verify.token, prompt, items: portfolio.items } }];

const prev = $('Build prompt').first().json;
const res = $input.first().json;
const text = res.candidates?.[0]?.content?.parts?.[0]?.text;
if (!text) throw new Error('Gemini no text: ' + JSON.stringify(res).slice(0,300));
let parsed;
try { parsed = JSON.parse(text); } catch (e) { throw new Error('Non-JSON: ' + text.slice(0,300)); }
if (!parsed.suggestions || !Array.isArray(parsed.suggestions)) throw new Error('Missing suggestions[]');

const itemMap = new Map(prev.items.map(i => [i.id, i]));
const issueItems = parsed.suggestions.filter(s => s && s.target_id && s.suggestion).map(s => {
  const existing = itemMap.get(s.target_id);
  const title = s.target_title || existing?.title || s.target_id;
  const verb = s.suggestion;
  const issueTitle = `[AED] ${verb}: ${title} (${s.target_id})`;
  const issueBody = `<!-- target_id: ${s.target_id} -->\n<!-- suggestion: ${verb} -->\n\n**AI 제안**: \`${verb}\`\n\n**대상**: ${title}\n\n**근거**: ${s.ai_reason || '(없음)'}\n\n---\n_AED 자동 생성. /mypage/issues에서 수용/거부를 결정하세요._`;
  return { owner: prev.owner, repo: prev.repo, token: prev.token, title: issueTitle, body: issueBody, labels: ['aed-suggestion'], target_id: s.target_id };
});

return [{ json: { suggestionCount: issueItems.length, issueItems, owner: prev.owner, repo: prev.repo, token: prev.token } }];

const items = $input.all();
const issues = items.map(i => ({ number: i.json.number, url: i.json.html_url, title: i.json.title })).filter(x => x.number);
return [{ json: { ok: true, count: issues.length, issues } }];
